import React, { useEffect, useState } from "react";

import SplashScreen from "./screens/SplashScreen";
import SignInScreen from "./screens/SignInScreen";
import SignUpScreen from "./screens/SignUpScreen";
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import SavingsDepositScreen from "./screens/SavingsDepositScreen";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen";
import TransactionsScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import AddMoneyOptionsScreen from "./screens/AddMoneyOptionsScreen";
import PaymentProcessingScreen from "./screens/PaymentProcessingScreen";
import PaymentSuccessScreen from "./screens/PaymentSuccessScreen";
import GoalsScreen from "./screens/GoalsScreen";
import LoansScreen from "./screens/LoansScreen";
import ProfileScreen from "./screens/ProfileScreen";
import BottomNav from "./components/BottomNav";

import { generateReference } from "./helpers/reference";


export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [activeTab, setActiveTab] = useState("home");
  const [darkMode, setDarkMode] = useState(false);

  // Auth
  const [user, setUser] = useState(null);

  // Money state
  const [balance, setBalance] = useState(0);
  const [savingsBalance, setSavingsBalance] = useState(0);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  /* ---------------- LOAD STORAGE ---------------- */
  useEffect(() => {
    const u = localStorage.getItem("user");
    const b = localStorage.getItem("balance");
    const s = localStorage.getItem("savingsBalance");
    const t = localStorage.getItem("transactions");

    if (u) setUser(JSON.parse(u));
    if (b) setBalance(Number(b));
    if (s) setSavingsBalance(Number(s));
    if (t) setTransactions(JSON.parse(t));
  }, []);

  /* ---------------- SAVE STORAGE ---------------- */
  useEffect(() => {
    if (user) localStorage.setItem("user", JSON.stringify(user));
    localStorage.setItem("balance", balance);
    localStorage.setItem("savingsBalance", savingsBalance);
    localStorage.setItem("transactions", JSON.stringify(transactions));
  }, [user, balance, savingsBalance, transactions]);

  /* ---------------- NAV HELPERS ---------------- */
  const openScreen = (screen, data = null) => {
    if (screen === "TransactionReceipt") {
      setSelectedTransaction(data);
    }
    setCurrentScreen(screen);
  };

  const goHome = () => {
    setCurrentScreen("Main");
    setActiveTab("home");
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.clear();
    setCurrentScreen("SignIn");
  };

  /* ---------------- TRANSACTIONS ---------------- */
  const addTransaction = (tx) => {
    setTransactions((prev) => [tx, ...prev]);
  };

  const handleDeposit = (amount) => {
    if (amount <= 0) return;
    setBalance((b) => b + amount);

    addTransaction({
      id: Date.now(),
      reference: generateReference(),
      title: "Deposit",
      amount,
      type: "deposit",
      date: new Date().toDateString(),
    });

    goHome();
  };

  const handleWithdraw = (amount) => {
    if (amount <= 0 || amount > balance) return;

    setBalance((b) => b - amount);

    addTransaction({
      id: Date.now(),
      reference: generateReference(),
      title: "Withdrawal",
      amount,
      type: "withdraw",
      date: new Date().toDateString(),
    });

    goHome();
  };

  const handleSavingsDeposit = (amount) => {
    if (amount <= 0 || amount > balance) return;
    setBalance((b) => b - amount);
    setSavingsBalance((s) => s + amount);
    goHome();
  };

  const handleSavingsWithdraw = (amount) => {
    if (amount <= 0 || amount > savingsBalance) return;
    setSavingsBalance((s) => s - amount);
    setBalance((b) => b + amount);
    goHome();
  };

  const commonScreenProps = {
    darkMode,
    toggleDarkMode: () => setDarkMode((d) => !d),
  };

  return (
    <div className={darkMode ? "bg-gray-900 text-white min-h-screen" : "bg-gray-50 text-gray-900 min-h-screen"}>

      {/* Splash */}
      {currentScreen === "Splash" && (
        <SplashScreen
          onFinish={() => setCurrentScreen(user ? "Main" : "SignIn")}
        />
      )}

      {/* Auth */}
      {currentScreen === "SignIn" && (
        <SignInScreen
          onSignIn={(u) => {
            setUser(u);
            goHome();
          }}
          onSwitch={() => setCurrentScreen("SignUp")}
        />
      )}

      {currentScreen === "SignUp" && (
        <SignUpScreen
          onSignUp={(u) => {
            setUser(u);
            goHome();
          }}
          onSwitch={() => setCurrentScreen("SignIn")}
        />
      )}

      {/* Main */}
      {currentScreen === "Main" && (
        <>
          {activeTab === "home" && (
            <HomeScreen
              {...commonScreenProps}
              balance={balance}
              savingsBalance={savingsBalance}
              transactions={transactions}
              userName={user?.name || "Pips"}
              openScreen={openScreen}
            />
          )}

          {activeTab === "goals" && <GoalsScreen {...commonScreenProps} />}
          {activeTab === "loans" && <LoansScreen {...commonScreenProps} />}
          {activeTab === "profile" && (
            <ProfileScreen
              {...commonScreenProps}
              user={user}
              onLogout={handleLogout}
            />
          )}

          <BottomNav active={activeTab} setActive={setActiveTab} />
        </>
      )}

      {/* Other Screens */}
      {currentScreen === "Deposit" && (
        <DepositScreen onDeposit={handleDeposit} onBack={goHome} />
      )}

      {currentScreen === "Withdraw" && (
        <WithdrawScreen onWithdraw={handleWithdraw} onBack={goHome} />
      )}

      {currentScreen === "SavingsDeposit" && (
        <SavingsDepositScreen onSave={handleSavingsDeposit} onBack={goHome} />
      )}

      {currentScreen === "SavingsWithdraw" && (
        <SavingsWithdrawScreen onWithdraw={handleSavingsWithdraw} onBack={goHome} />
      )}

      {currentScreen === "Transactions" && (
        <TransactionsScreen
          transactions={transactions}
          openReceipt={(t) => openScreen("TransactionReceipt", t)}
          onBack={goHome}
        />
      )}

      {currentScreen === "TransactionReceipt" && (
        <TransactionReceiptScreen
          transaction={selectedTransaction}
          onBack={() => openScreen("Transactions")}
        />
      )}

          {currentScreen === "PaymentProcessing" && (
        <PaymentProcessingScreen
          onBack={() => setCurrentScreen("PaymentSuccess")}
        />
      )}


      {currentScreen === "PaymentSuccess" && (
        <PaymentSuccessScreen
          transaction={{ amount: 1000, reference: "ABC123" }}
          onBack={goHome}
        />
      )}
          {currentScreen === "AddMoneyOptions" && (
      <AddMoneyOptionsScreen
        onBack={goHome}
        onSelectOption={() => setCurrentScreen("PaymentProcessing")}
      />
    )}
    </div>
  );
}
